import os
import sys
import json
import gzip

sys.stdout.reconfigure(line_buffering=True)
sys.stderr.reconfigure(line_buffering=True)

def incarc_index_master_gz(cale_local_sau_stream):
    try:
        with gzip.open(cale_local_sau_stream, "rb") as f:
            date = json.loads(f.read().decode('utf-8'))
            print(f"✅ [INDEX READER] Master Index încărcat cu succes ({len(date)} intrări).", flush=True)
            return date
    except Exception as e:
        print(f"⚠️ [INDEX READER] Nu s-a putut citi indexul comprimat (.gz): {e}", flush=True)
        return {}

def salveaza_index_master_gz(date_index, cale_salvare):
    try:
        with gzip.open(cale_salvare, "wb") as f:
            f.write(json.dumps(date_index, ensure_ascii=False, indent=2).encode('utf-8'))
        print(f"💾 [INDEX READER] Master Index salvat comprimat la: {cale_salvare}", flush=True)
        return True
    except Exception as e:
        print(f"🛑 [INDEX READER] Eroare la salvarea indexului master: {e}", flush=True)
        return False

def proceseaza_si_curata_microindecsi(service_drive, master_index_data, list_micro_index_files, batch_size=50):
    total_fisiere = len(list_micro_index_files)
    if total_fisiere == 0:
        print("✨ [MICRO-INDEX] Nu există micro-indecși de procesat.", flush=True)
        return master_index_data

    print(f"⚡ [MICRO-INDEX] Începe procesarea a {total_fisiere} micro-indecși în batch-uri de {batch_size}...", flush=True)

    for i in range(0, total_fisiere, batch_size):
        batch = list_micro_index_files[i : i + batch_size]
        fisiere_de_sters_ids = []

        for micro_file in batch:
            try:
                micro_data = micro_file.get("content_json", {})
                for cheie, info in micro_data.items():
                    master_index_data[cheie] = info
                fisiere_de_sters_ids.append(micro_file["id"])
            except Exception as e:
                print(f"⚠️ [MICRO-INDEX] Eroare citire micro-index {micro_file.get('name')}: {e}", flush=True)

        for file_id in fisiere_de_sters_ids:
            try:
                service_drive.files().delete(fileId=file_id, supportsAllDrives=True).execute()
            except Exception as e:
                print(f"⚠️ [MICRO-INDEX] Eroare ștergere micro-index {file_id}: {e}", flush=True)

        print(f"✅ [MICRO-INDEX] Batch {i // batch_size + 1} integrat și curățat ({len(fisiere_de_sters_ids)} fișiere șterse).", flush=True)

    print(f"🎉 [MICRO-INDEX] Toți micro-indecșii au fost procesați și șterși!", flush=True)
    return master_index_data
